INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Donkey_Calf_Raises','Donkey Calf Raises','pantorrillas',ARRAY[]::text[],'otro','strength',ARRAY['For this exercise you will need access to a donkey calf raise machine. Start by positioning your lower back and hips under the padded lever provided. The tailbone area should be the one making contact with the pad.','Place both of your arms on the side handles and place the balls of your feet on the calf block with the heels extending off. Align the toes forward, inward or outward, depending on the area you wish to target, and straighten the knees without locking them. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'],'For this exercise you will need access to a donkey calf raise machine. Start by positioning your lower back and hips under the padded lever provided. The tailbone area should be the one making contact with the pad. Place both of your arms on the side handles and place the balls of your feet on the calf block with the heels extending off. Align the toes forward, inward or outward, depending on the area you wish to target, and straighten the knees without locking them. This will be your starting position. Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down. Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Donkey_Calf_Raises/0.jpg','exercisedb',true),('Double_Kettlebell_Alternating_Hang_Clean','Double Kettlebell Alternating Hang Clean','isquiotibiales',ARRAY['bíceps','pantorrillas','antebrazos','glúteos','espalda baja','cuádriceps','trapecios'],'kettlebells','strength',ARRAY['Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean one kettlebell to your shoulder and hold on to the other kettlebell.','With a fluid motion, lower the top kettlebell while driving the bottom kettlebell up.'],'Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead. Clean one kettlebell to your shoulder and hold on to the other kettlebell. With a fluid motion, lower the top kettlebell while driving the bottom kettlebell up.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Alternating_Hang_Clean/0.jpg','exercisedb',true),('Double_Kettlebell_Jerk','Double Kettlebell Jerk','hombros',ARRAY['pantorrillas','cuádriceps','tríceps'],'kettlebells','strength',ARRAY['Hold a kettlebell by the handle in each hand.','Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum.','As you do so, press the kettlebells overhead to lockout by extending the arms, using your body''''s momentum to move the weights.','Return your feet to the ground in a split fashion, with one foot forward and one foot back.','Keeping the weights overhead, return to a standing position, bringing your feet together. Lower the weights to perform the next repetition.'],'Hold a kettlebell by the handle in each hand. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. This will be your starting position. Dip your body by bending the knees, keeping your torso upright. Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebells overhead to lockout by extending the arms, using your body''s momentum to move the weights. Return your feet to the ground in a split fashion, with one foot forward and one foot back. Keeping the weights overhead, return to a standing position, bringing your feet together. Lower the weights to perform the next repetition.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Jerk/0.jpg','exercisedb',true),('Double_Kettlebell_Push_Press','Double Kettlebell Push Press','hombros',ARRAY['pantorrillas','cuádriceps','tríceps'],'kettlebells','strength',ARRAY['Clean two kettlebells to your shoulders.','Squat down a few inches and reverse the motion rapidly. Use the momentum from the legs to drive the kettlebells overhead.','Once the kettlebells are locked out, lower the kettlebells to your shoulders and repeat.'],'Clean two kettlebells to your shoulders. Squat down a few inches and reverse the motion rapidly. Use the momentum from the legs to drive the kettlebells overhead. Once the kettlebells are locked out, lower the kettlebells to your shoulders and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Push_Press/0.jpg','exercisedb',true),('Double_Kettlebell_Snatch','Double Kettlebell Snatch','hombros',ARRAY['glúteos','isquiotibiales','cuádriceps'],'kettlebells','strength',ARRAY['Place two kettlebells behind your feet. Bend your knees and sit back to pick up the kettlebells.','Swing the kettlebells between your legs forcefully and reverse the direction.','Drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.'],'Place two kettlebells behind your feet. Bend your knees and sit back to pick up the kettlebells. Swing the kettlebells between your legs forcefully and reverse the direction. Drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Snatch/0.jpg','exercisedb',true),('Double_Kettlebell_Windmill','Double Kettlebell Windmill','abdominales',ARRAY['glúteos','isquiotibiales','hombros','tríceps'],'kettlebells','strength',ARRAY['Place a kettlebell in front of your front foot and clean and press a kettlebell overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward.','Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell.','Bending at the hip to one side, sticking your butt out, slowly lean until you can retrieve the kettlebell from the floor. Keep your eyes on the kettlebell that you hold over your head at all times.','Pause for a second after retrieving the kettlebell from the ground and reverse the motion back to the starting position.'],'Place a kettlebell in front of your front foot and clean and press a kettlebell overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can retrieve the kettlebell from the floor. Keep your eyes on the kettlebell that you hold over your head at all times. Pause for a second after retrieving the kettlebell from the ground and reverse the motion back to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Windmill/0.jpg','exercisedb',true),('Double_Leg_Butt_Kick','Double Leg Butt Kick','cuádriceps',ARRAY['abductores','aductores','pantorrillas','glúteos','isquiotibiales'],'peso corporal','plyometrics',ARRAY['Begin standing with your knees slightly bent.','Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height.','As you go up, tuck your heels by flexing the knees, attempting to touch the buttocks.','Finish the motion by landing with the knees only partially bent, using your legs to absorb the impact.'],'Begin standing with your knees slightly bent. Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height. As you go up, tuck your heels by flexing the knees, attempting to touch the buttocks. Finish the motion by landing with the knees only partially bent, using your legs to absorb the impact.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Leg_Butt_Kick/0.jpg','exercisedb',true),('Downward_Facing_Balance','Downward Facing Balance','glúteos',ARRAY['abdominales','isquiotibiales'],'pelota de ejercicio','strength',ARRAY['Lie facedown on top of an exercise ball.','While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees.'],'Lie facedown on top of an exercise ball. While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Downward_Facing_Balance/0.jpg','exercisedb',true),('Drag_Curl','Drag Curl','bíceps',ARRAY['antebrazos'],'barra','strength',ARRAY['Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position.','As you exhale, curl the bar up while keeping the elbows to the back as you "Drag" the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders.','Slowly go back to the starting position as you keep the bar in contact with the torso at all times.','Repeat for the recommended amount of repetitions.'],'Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position. As you exhale, curl the bar up while keeping the elbows to the back as you "Drag" the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders. Slowly go back to the starting position as you keep the bar in contact with the torso at all times. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Drag_Curl/0.jpg','exercisedb',true),('Drop_Push','Drop Push','pecho',ARRAY['hombros','tríceps'],'otro','plyometrics',ARRAY['Position low boxes or other platforms 2-3 feet apart.','Move to a pushup position between them, supporting yourself by placing your hands on the boxes.','With good posture, drop from the platforms by pressing up and moving your hands to shoulder width, cushioning your landing by absorbing the impact through the arm.'],'Position low boxes or other platforms 2-3 feet apart. Move to a pushup position between them, supporting yourself by placing your hands on the boxes. With good posture, drop from the platforms by pressing up and moving your hands to shoulder width, cushioning your landing by absorbing the impact through the arm.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Drop_Push/0.jpg','exercisedb',true);